(function () {
    let opened = false;

    console.log("MeetFlow Widget Loaded");

    if (document.getElementById("meetflow-launcher"))
        return;

    const launcher = document.createElement("div");

    launcher.id = "meetflow-launcher";

    launcher.innerHTML = "MF";

    launcher.style.position = "fixed";

    launcher.style.right = "30px";

    launcher.style.bottom = "40px";

    launcher.style.width = "60px";

    launcher.style.height = "60px";

    launcher.style.borderRadius = "50%";

    launcher.style.background = "#2563eb";

    launcher.style.display = "flex";

    launcher.style.justifyContent = "center";

    launcher.style.alignItems = "center";

    launcher.style.color = "#fff";

    launcher.style.fontSize = "20px";

    launcher.style.cursor = "pointer";

    launcher.style.boxShadow = "0 10px 25px rgba(0,0,0,.25)";

    launcher.style.zIndex = "2147483647";

    launcher.style.transition =
        `
        transform .3s cubic-bezier(.22,.61,.36,1),
        background .25s ease,
        box-shadow .25s ease
        `;

    launcher.onmouseenter = () => {

        if (opened) {
            launcher.style.transform = "rotate(90deg) scale(1.08)";
        } else {
            launcher.style.transform = "rotate(0deg) scale(1.08)";
        }

    };

    launcher.onmouseleave = () => {

        if (opened) {
            launcher.style.transform = "rotate(90deg)";
        } else {
            launcher.style.transform = "rotate(0deg)";
        }

    };

    document.body.appendChild(launcher);

    const frame = document.createElement("iframe");

    frame.src = "https://meetflow-j39a.onrender.com/widget";
    frame.allow = "camera; microphone; autoplay; fullscreen; display-capture";

    frame.style.position = "fixed";

    frame.style.right = "20px";

    frame.style.bottom = "90px";

    frame.style.width = "380px";

    frame.style.height = "600px";

    frame.style.border = "0";

    frame.style.borderRadius = "15px";

    frame.style.boxShadow = "0 10px 25px rgba(0,0,0,.25)";

    // frame.style.display = "none";
    frame.style.opacity = "0";
    frame.style.transform = "translateY(40px) scale(0.9)";
    frame.style.pointerEvents = "none";
    frame.style.transition = "opacity .25s ease, transform .35s cubic - bezier(.22, .61, .36, 1)";

    frame.style.zIndex = "2147483647";

    document.body.appendChild(frame);

    launcher.onclick = () => {

        if (opened) {
            closeWidget();
        } else {
            openWidget();
        }

    };

    window.addEventListener("message", (e) => {

        if (e.origin !== "https://meetflow-j39a.onrender.com")
            return;

        if (e.data.type === "MEETFLOW_CLOSE") {

            // frame.style.display = "none";
            frame.style.opacity = "0";
            frame.style.transform = "translateY(20px) scale(0.9)";
            frame.style.pointerEvents = "none";

            launcher.innerHTML = "MF";

            opened = false;

        }

    });

    function openWidget() {

        frame.style.pointerEvents = "auto";

        requestAnimationFrame(() => {

            frame.style.opacity = "1";
            frame.style.transform =
                "translateY(0) scale(1)";

        });

        launcher.innerHTML =
            '<i class="fa-solid fa-xmark"></i>';

        launcher.style.transform = "rotate(90deg)";
        launcher.style.background = "#ef4444";

        opened = true;

    }

    function closeWidget() {

        frame.style.opacity = "0";

        frame.style.transform =
            "translateY(20px) scale(.9)";

        frame.style.pointerEvents = "none";

        launcher.innerHTML = "MF";

        launcher.style.transform = "rotate(0deg)";

        opened = false;

    }

})();